import subprocess, sys
base='origin/main'
orig='55f84aa7bca3dc98977be18d39c554af16a8b4e5'
files=subprocess.check_output(['git','diff','--name-only',base,orig], text=True).splitlines()

def group(path):
    parts=path.split('/')
    if path.startswith('src/app/'):
        sub=parts[2] if len(parts)>2 else ''
        if sub in {'admin','core','global-admin','templates','shared'} or path.startswith('src/app/app.') or path == 'src/app/AGENTS.md':
            return 'app-surfaces'
        return 'e2e-docs'
    if path.startswith('tests/'):
        return 'e2e-docs'
    if path.startswith('src/server/') or path.startswith('src/shared/'):
        return 'server-contracts'
    if path.startswith('src/db/') or path.startswith('src/types/'):
        return 'infra-runtime'
    return 'infra-runtime'

groups={name:[] for name in ['infra-runtime','server-contracts','app-surfaces','e2e-docs']}
for f in files:
    groups[group(f)].append(f)
for name, fs in groups.items():
    print(name, len(fs))
    if len(fs)>150:
        print('too many', name, file=sys.stderr); sys.exit(1)
fs=groups['infra-runtime']
patch=subprocess.check_output(['git','diff','--binary',base,orig,'--',*fs])
if not patch:
    print('no patch')
else:
    p=subprocess.run(['git','apply','--index'], input=patch)
    if p.returncode:
        sys.exit(p.returncode)
