    code?: unknown;
    raw?: { code?: unknown };
    type?: unknown;
  };
  return (
    candidate.type === 'StripeInvalidRequestError' &&
    (candidate.code === 'resource_missing' ||
      candidate.raw?.code === 'resource_missing')
  );
};

